57	const FIRST_INSURANCE_RATE = 0.1;
58	const PROCESSING_FEE = 5;
59	const LOYALTY_THRESHOLD_YEARS = 2;
60	const LOYALTY_DISCOUNT_RATE = 0.2;
61	const FOLLOWUP_DISCOUNT_RATE = 0.15;
62	const DEDUCTIBLE = 100;
63	
64	const COMPONENT_TYPES = ["rune", "moonstone"];
65	const COMPONENT_BLOCK_SIZE = 3;
66	const COMPONENT_BLOCK_PREMIUM = 60;
67	
68	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
69	
70	const typeBasePremium = (type: string, count: number): number =>
71	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
72	    ? COMPONENT_BLOCK_PREMIUM
73	    : count * BASE_PREMIUM[type];
74	
75	const CURSE_RATE = 0.5;
76	const HIGH_ENCHANTMENT_THRESHOLD = 5;
77	const HIGH_ENCHANTMENT_RATE = 0.3;
78	
79	const surchargeForItem = (item: Item): number => {
80	  const base = BASE_PREMIUM[item.type];
81	  const curse = item.cursed ? CURSE_RATE * base : 0;
82	  const highEnchantment =
83	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
84	      ? HIGH_ENCHANTMENT_RATE * base
85	      : 0;
86	  return curse + highEnchantment;
87	};
88	
89	const itemSurcharges = (items: Item[]): number =>
90	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
91	
92	const countByType = (items: Item[]): Map<string, number> => {
93	  const counts = new Map<string, number>();
94	  for (const item of items) {
95	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
96	  }
97	  return counts;
98	};
99	
100	const policyBasePremium = (items: Item[]): number =>
101	  [...countByType(items)].reduce(
102	    (total, [type, count]) => total + typeBasePremium(type, count),
103	    0,
104	  );
105	
106	const isLoyal = (customer: Customer): boolean =>
107	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
108	
109	const policyModifierRate = (customer: Customer, isFollowup: boolean): number =>
110	  FIRST_INSURANCE_RATE -
111	  (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0) -
112	  (isFollowup ? FOLLOWUP_DISCOUNT_RATE : 0);
113	
114	const quotePremium = (
115	  step: QuoteStep,
116	  customer: Customer,
117	  isFollowup: boolean,
118	): number => {
119	  const policyBase = policyBasePremium(step.items);
120	  const policyModifierAmount =
121	    policyBase * policyModifierRate(customer, isFollowup);
122	  return Math.ceil(
123	    policyBase +
124	      itemSurcharges(step.items) +
125	      policyModifierAmount +
126	      PROCESSING_FEE,
127	  );
128	};
129	
130	const insuranceSum = (items: Item[]): number =>
131	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
132	
133	const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
134	  const cap = 2 * insuranceSum(policyItems);
135	  const payout = step.incident.damages.reduce(
136	    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
137	    0,
138	  );
139	  return { payout: Math.floor(payout), remainingCap: cap - payout };
140	};
