142	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
143	  const policyItemsByStep = new Map<number, Item[]>();
144	  let quoteCount = 0;
145	  const results: StepResult[] = [];
146	  scenario.steps.forEach((step, index) => {
147	    if (step.op === "quote") {
148	      results.push({
149	        premium: quotePremium(step, scenario.customer, quoteCount > 0),
150	      });
151	      policyItemsByStep.set(index, step.items);
152	      quoteCount += 1;
153	    } else {
154	      results.push(claimResult(step, policyItemsByStep.get(step.policy) ?? []));
155	    }
156	  });
157	  return { results };
158	};
