export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const policyItemsByStep = new Map<number, Item[]>();
  let quoteCount = 0;
  const results: StepResult[] = [];
  scenario.steps.forEach((step, index) => {
    if (step.op === "quote") {
      const isFollowup = quoteCount > 0;
      results.push({ premium: quotePremium(step, scenario.customer, isFollowup) });
      policyItemsByStep.set(index, step.items);
      quoteCount += 1;
    } else {
      const policyItems = policyItemsByStep.get(step.policy) ?? [];
      results.push(claimResult(step, policyItems));
    }
  });
  return { results };
};
